#include <bits/stdc++.h>

#define ll long long
#define MOD 1000000007
#define MAXN 100000
#define INF 100000000000000000

using namespace std;

class Solution {
public:
    int solve(vector<int>& coins, int x) {
        sort(coins.begin(), coins.end(), greater<int>());
        int result = 0;
        for (int coin : coins) {
            int count = x / coin;
            if (count > 0) {
                x -= count * coin;
                result += count;
            }
        }
        return x == 0 ? result : -1;
    }
};

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);
    Solution s;
    int t;
    cin >> t;
    while (t--) {
        int n, x;
        cin >> n >> x;
        vector<int> coins(n);
        for (int& coin : coins) {
            cin >> coin;
        }
        cout << s.solve(coins, x) << endl;
    }
    return 0;
}
